import React, { useState, useEffect } from 'react';
import { useNavigate, useLocation } from 'react-router-dom';

const Navbar = ({ activeMenu, setActiveMenu, isAuthenticated, handleLogout, userRole, theme, toggleTheme }) => {
    const navigate = useNavigate();
    const location = useLocation();
    const [hoveredMenu, setHoveredMenu] = useState(null);
    const [mobileMenuOpen, setMobileMenuOpen] = useState(false);
    const [scrolled, setScrolled] = useState(false);

    const isDark = theme === 'dark';

    // Handle scroll effect
    useEffect(() => {
        const handleScroll = () => {
            setScrolled(window.scrollY > 50);
        };
        window.addEventListener('scroll', handleScroll);
        return () => window.removeEventListener('scroll', handleScroll);
    }, []);

    const navigateTo = (path, menuId) => {
        if (setActiveMenu) setActiveMenu(menuId);
        navigate(path);
        setMobileMenuOpen(false);
    };

    const getMenuStyle = (menuId) => ({
        background: 'none', 
        border: 'none',
        color: hoveredMenu === menuId || (activeMenu === menuId && location.pathname === '/') ? '#ea580c' : (isDark ? '#fff' : '#1c1917'),
        fontWeight: '700', 
        cursor: 'pointer', 
        fontSize: '14px', 
        transition: 'all 0.3s ease',
        padding: '8px 0',
        position: 'relative',
        letterSpacing: '0.3px'
    });

    const isActiveRoute = (path) => {
        if (path === '/' && location.pathname === '/') return true;
        if (path !== '/' && location.pathname.startsWith(path)) return true;
        return false;
    };

    return (
        <>
            <nav style={{ 
                display: 'flex', 
                justifyContent: 'space-between', 
                alignItems: 'center', 
                padding: scrolled ? '15px 5%' : '20px 5%', 
                background: scrolled 
                    ? (isDark ? 'rgba(12, 10, 9, 0.95)' : 'rgba(245, 245, 244, 0.95)')
                    : (isDark ? '#0c0a09' : '#f5f5f4'), 
                borderBottom: `1px solid ${isDark ? '#262626' : '#e5e5e5'}`,
                position: 'sticky',
                top: 0,
                zIndex: 1000,
                transition: 'all 0.3s ease',
                backdropFilter: scrolled ? 'blur(10px)' : 'none'
            }}>
                <div 
                    onClick={() => navigateTo('/', 'home')} 
                    style={{ 
                        cursor: 'pointer',
                        transition: 'all 0.3s ease'
                    }}
                    onMouseEnter={(e) => {
                        e.currentTarget.style.transform = 'scale(1.02)';
                    }}
                    onMouseLeave={(e) => {
                        e.currentTarget.style.transform = 'scale(1)';
                    }}
                >
                    <h2 style={{ 
                        color: isDark ? '#fef3c7' : '#1c1917', 
                        margin: 0, 
                        fontSize: '22px',
                        fontWeight: '800',
                        letterSpacing: '-0.5px'
                    }}>
                        Pasukan<span style={{ color: '#ea580c' }}>Yerus</span>Solo
                    </h2>
                </div>

                {/* Desktop Menu */}
                <div className="nav-menu" style={{ display: 'flex', gap: '30px', alignItems: 'center' }}>
                    <button 
                        style={getMenuStyle('home')} 
                        onClick={() => navigateTo('/', 'home')} 
                        onMouseEnter={() => setHoveredMenu('home')} 
                        onMouseLeave={() => setHoveredMenu(null)}
                    >
                        Beranda
                        {isActiveRoute('/') && (
                            <span style={{
                                position: 'absolute',
                                bottom: '0',
                                left: '0',
                                width: '100%',
                                height: '2px',
                                background: '#ea580c',
                                borderRadius: '2px'
                            }} />
                        )}
                    </button>
                    <button 
                        style={getMenuStyle('lowongan')} 
                        onClick={() => navigateTo('/eksplorasi', 'lowongan')} 
                        onMouseEnter={() => setHoveredMenu('lowongan')} 
                        onMouseLeave={() => setHoveredMenu(null)}
                    >
                        Lowongan
                        {isActiveRoute('/eksplorasi') && (
                            <span style={{
                                position: 'absolute',
                                bottom: '0',
                                left: '0',
                                width: '100%',
                                height: '2px',
                                background: '#ea580c',
                                borderRadius: '2px'
                            }} />
                        )}
                    </button>

                    {/* Menu hanya muncul untuk akun dengan role Perusahaan */}
                    {isAuthenticated && userRole === 'Perusahaan' && (
                        <>
                            <button 
                                onClick={() => navigate('/hrd/dashboard')}
                                style={{
                                    background: 'none',
                                    border: 'none',
                                    color: hoveredMenu === 'dashboard' ? '#ea580c' : (isDark ? '#fff' : '#1c1917'),
                                    fontWeight: '700',
                                    cursor: 'pointer',
                                    fontSize: '14px',
                                    transition: 'all 0.3s ease',
                                    padding: '8px 0'
                                }}
                                onMouseEnter={() => setHoveredMenu('dashboard')}
                                onMouseLeave={() => setHoveredMenu(null)}
                            >
                                Dashboard
                            </button>
                            <button 
                                onClick={() => navigate('/hrd/branding')}
                                style={{
                                    background: 'none',
                                    border: 'none',
                                    color: hoveredMenu === 'branding' ? '#ea580c' : (isDark ? '#fff' : '#1c1917'),
                                    fontWeight: '700',
                                    cursor: 'pointer',
                                    fontSize: '14px',
                                    transition: 'all 0.3s ease',
                                    padding: '8px 0'
                                }}
                                onMouseEnter={() => setHoveredMenu('branding')}
                                onMouseLeave={() => setHoveredMenu(null)}
                            >
                                Branding
                            </button>
                        </>
                    )}
                </div>

                <div style={{ display: 'flex', alignItems: 'center', gap: '15px' }}>
                    {/* Theme Toggle Button */}
                    <button
                        onClick={toggleTheme}
                        style={{
                            background: isDark ? '#1c1917' : '#e5e5e5',
                            border: `1px solid ${isDark ? '#262626' : '#d4d4d4'}`,
                            borderRadius: '50%',
                            width: '40px',
                            height: '40px',
                            cursor: 'pointer',
                            display: 'flex',
                            alignItems: 'center',
                            justifyContent: 'center',
                            transition: 'all 0.3s ease',
                            fontSize: '18px'
                        }}
                        onMouseEnter={(e) => {
                            e.currentTarget.style.transform = 'scale(1.1)';
                            e.currentTarget.style.boxShadow = '0 2px 10px rgba(0,0,0,0.2)';
                        }}
                        onMouseLeave={(e) => {
                            e.currentTarget.style.transform = 'scale(1)';
                            e.currentTarget.style.boxShadow = 'none';
                        }}
                    >
                        {isDark ? '☀️' : '🌙'}
                    </button>

                    {isAuthenticated ? (
                        <button 
                            onClick={handleLogout} 
                            style={{ 
                                padding: '8px 20px', 
                                borderRadius: '30px', 
                                border: '1px solid #ef4444', 
                                color: '#ef4444', 
                                cursor: 'pointer', 
                                background: 'transparent',
                                fontWeight: '600',
                                fontSize: '13px',
                                transition: 'all 0.3s ease'
                            }}
                            onMouseEnter={(e) => {
                                e.currentTarget.style.background = '#ef4444';
                                e.currentTarget.style.color = '#fff';
                                e.currentTarget.style.transform = 'translateY(-2px)';
                            }}
                            onMouseLeave={(e) => {
                                e.currentTarget.style.background = 'transparent';
                                e.currentTarget.style.color = '#ef4444';
                                e.currentTarget.style.transform = 'translateY(0)';
                            }}
                        >
                            Keluar
                        </button>
                    ) : (
                        <button 
                            onClick={() => navigate('/login')} 
                            style={{ 
                                padding: '8px 24px', 
                                borderRadius: '30px', 
                                border: '1px solid #ea580c', 
                                background: hoveredMenu === 'login' ? '#ea580c' : 'transparent', 
                                color: hoveredMenu === 'login' ? '#fff' : '#ea580c', 
                                fontWeight: '700', 
                                fontSize: '13px', 
                                cursor: 'pointer', 
                                transition: 'all 0.3s ease',
                                boxShadow: hoveredMenu === 'login' ? '0 4px 15px rgba(234,88,12,0.3)' : 'none'
                            }}
                            onMouseEnter={(e) => {
                                setHoveredMenu('login');
                                e.currentTarget.style.transform = 'translateY(-2px)';
                            }}
                            onMouseLeave={(e) => {
                                setHoveredMenu(null);
                                e.currentTarget.style.transform = 'translateY(0)';
                            }}
                        >
                            Login
                        </button>
                    )}

                    {/* Mobile menu button */}
                    <button 
                        onClick={() => setMobileMenuOpen(!mobileMenuOpen)}
                        style={{
                            display: 'none',
                            background: 'none',
                            border: 'none',
                            color: isDark ? '#fff' : '#1c1917',
                            fontSize: '24px',
                            cursor: 'pointer',
                            padding: '8px'
                        }}
                        className="mobile-menu-btn"
                    >
                        ☰
                    </button>
                </div>
            </nav>

            {/* Mobile Menu */}
            {mobileMenuOpen && (
                <div style={{
                    position: 'fixed',
                    top: 0,
                    left: 0,
                    right: 0,
                    bottom: 0,
                    background: isDark ? '#0c0a09' : '#f5f5f4',
                    zIndex: 999,
                    padding: '80px 40px',
                    animation: 'slideIn 0.3s ease'
                }}>
                    <button 
                        onClick={() => setMobileMenuOpen(false)}
                        style={{
                            position: 'absolute',
                            top: '20px',
                            right: '20px',
                            background: 'none',
                            border: 'none',
                            color: isDark ? '#fff' : '#1c1917',
                            fontSize: '30px',
                            cursor: 'pointer'
                        }}
                    >
                        ✕
                    </button>
                    <div style={{ display: 'flex', flexDirection: 'column', gap: '30px', alignItems: 'center' }}>
                        <button onClick={() => navigateTo('/', 'home')} style={getMenuStyle('home')}>Beranda</button>
                        <button onClick={() => navigateTo('/eksplorasi', 'lowongan')} style={getMenuStyle('lowongan')}>Lowongan</button>
                        {isAuthenticated && userRole === 'Perusahaan' && (
                            <>
                                <button onClick={() => navigate('/hrd/dashboard')} style={{ color: isDark ? '#fff' : '#1c1917', background: 'none', border: 'none', fontSize: '18px' }}>Dashboard</button>
                                <button onClick={() => navigate('/hrd/branding')} style={{ color: isDark ? '#fff' : '#1c1917', background: 'none', border: 'none', fontSize: '18px' }}>Branding</button>
                            </>
                        )}
                        {isAuthenticated ? (
                            <button onClick={handleLogout} style={{ padding: '10px 30px', borderRadius: '30px', border: '1px solid #ef4444', color: '#ef4444', background: 'transparent' }}>Keluar</button>
                        ) : (
                            <button onClick={() => navigate('/login')} style={{ padding: '10px 30px', borderRadius: '30px', background: '#ea580c', color: '#fff', border: 'none' }}>Login</button>
                        )}
                    </div>
                </div>
            )}

            <style>{`
                @keyframes slideIn {
                    from {
                        transform: translateX(100%);
                    }
                    to {
                        transform: translateX(0);
                    }
                }
                @media (max-width: 768px) {
                    .nav-menu {
                        display: none !important;
                    }
                    .mobile-menu-btn {
                        display: block !important;
                    }
                }
            `}</style>
        </>
    );
};

export default Navbar;
